import{B as s}from"./BaseBreadcrumbs-D2EQ1GoT.js";import{d as v,c as i,a as t,b as e,e as l,w as o,h as n,i as r,k as p,_ as h}from"./index-CIW3DgOy.js";const u={class:"delivery-view"},m={class:"container"},_={class:"delivery-cta"},y=v({__name:"DeliveryView",setup(b){const d=[{label:"Главная",to:"/"},{label:"Доставка"}];return(f,a)=>{const c=n("router-link");return r(),i("main",u,[t("div",m,[e(s,{items:d}),a[3]||(a[3]=l('<h1 class="page-title" data-v-3e5570c3>Доставка</h1><section class="delivery-intro" data-v-3e5570c3><p data-v-3e5570c3> Компания «ГрузЭкспресс» обеспечивает надёжную доставку грузов по всей России. Мы предлагаем гибкие условия и различные варианты транспортировки, чтобы каждый клиент получил оптимальное решение для своих задач. </p></section><section class="delivery-section" data-v-3e5570c3><h2 data-v-3e5570c3>Зоны доставки</h2><div class="delivery-zones" data-v-3e5570c3><div class="zone-card" data-v-3e5570c3><div class="zone-icon" data-v-3e5570c3>🏙️</div><h3 data-v-3e5570c3>По городу</h3><p data-v-3e5570c3> Доставка в пределах города осуществляется в течение нескольких часов после оформления заказа. Мы работаем во всех районах и микрорайонах, обеспечивая максимальную оперативность. </p><ul class="zone-features" data-v-3e5570c3><li data-v-3e5570c3>Срок доставки — от 1 до 4 часов</li><li data-v-3e5570c3>Бесплатная подача транспорта</li><li data-v-3e5570c3>Грузчики включены в стоимость</li></ul></div><div class="zone-card" data-v-3e5570c3><div class="zone-icon" data-v-3e5570c3>🌆</div><h3 data-v-3e5570c3>По области</h3><p data-v-3e5570c3> Перевозки в пределах области выполняются в течение одного рабочего дня. Мы охватываем все пригородные районы и ближайшие населённые пункты. </p><ul class="zone-features" data-v-3e5570c3><li data-v-3e5570c3>Срок доставки — до 24 часов</li><li data-v-3e5570c3>Фиксированная стоимость по тарифам</li><li data-v-3e5570c3>Отслеживание на всех этапах</li></ul></div><div class="zone-card" data-v-3e5570c3><div class="zone-icon" data-v-3e5570c3>🗺️</div><h3 data-v-3e5570c3>По России</h3><p data-v-3e5570c3> Межгородские перевозки в любую точку России. Мы работаем с крупными транспортными компаниями и обеспечиваем надёжную доставку на дальние расстояния. </p><ul class="zone-features" data-v-3e5570c3><li data-v-3e5570c3>Срок доставки — от 1 до 14 дней</li><li data-v-3e5570c3>Расчёт стоимости по весу и объёму</li><li data-v-3e5570c3>Страхование груза</li></ul></div></div></section><section class="delivery-times" data-v-3e5570c3><h2 data-v-3e5570c3>Сроки доставки</h2><p data-v-3e5570c3> Время доставки зависит от удалённости адреса, объёма груза и загруженности транспортных маршрутов. Для городских перевозок стандартный срок — до 4 часов с момента оформления заявки. Межгородские перевозки рассчитываются индивидуально. </p><div class="times-table" data-v-3e5570c3><table data-v-3e5570c3><thead data-v-3e5570c3><tr data-v-3e5570c3><th data-v-3e5570c3>Тип доставки</th><th data-v-3e5570c3>Минимальный срок</th><th data-v-3e5570c3>Максимальный срок</th></tr></thead><tbody data-v-3e5570c3><tr data-v-3e5570c3><td data-v-3e5570c3>По городу</td><td data-v-3e5570c3>1 час</td><td data-v-3e5570c3>4 часа</td></tr><tr data-v-3e5570c3><td data-v-3e5570c3>По области</td><td data-v-3e5570c3>3 часа</td><td data-v-3e5570c3>24 часа</td></tr><tr data-v-3e5570c3><td data-v-3e5570c3>По России (ближние регионы)</td><td data-v-3e5570c3>1 день</td><td data-v-3e5570c3>3 дня</td></tr><tr data-v-3e5570c3><td data-v-3e5570c3>По России (дальние регионы)</td><td data-v-3e5570c3>3 дня</td><td data-v-3e5570c3>14 дней</td></tr></tbody></table></div></section><section class="delivery-cost" data-v-3e5570c3><h2 data-v-3e5570c3>Стоимость доставки</h2><p data-v-3e5570c3> Стоимость формируется на основе нескольких факторов: расстояние, вес и объём груза, необходимость грузчиков, этаж забора и доставки. Для городских перевозок действует минимальный тариф — от 1 500 ₽. Межгородские перевозки рассчитываются индивидуально после получения заявки. </p><p data-v-3e5570c3> Мы всегда стараемся предложить конкурентоспособные цены и готовы обсудить индивидуальные условия для постоянных клиентов и крупных заказов. </p></section><section class="delivery-tracking" data-v-3e5570c3><h2 data-v-3e5570c3>Отслеживание груза</h2><p data-v-3e5570c3> Все заказы сопровождаются отслеживанием на каждом этапе доставки. После оформления заказа вы получаете уникальный номер, по которому можете узнать актуальный статус вашего груза. Наша служба поддержки работает круглосуточно и готова предоставить информацию о местоположении вашего заказа в любой момент. </p><p data-v-3e5570c3> Для отслеживания заказа перейдите в личный кабинет, раздел «Мои заказы», или свяжитесь с нами по телефону +7 (800) 555-35-35. </p></section><section class="delivery-special" data-v-3e5570c3><h2 data-v-3e5570c3>Особые условия</h2><p data-v-3e5570c3> Для некоторых типов грузов действуют особые условия доставки. Хрупкие предметы, ценное оборудование, опасные грузы — каждый тип перевозок требует соблюдения специальных правил. Наши менеджеры подберут оптимальные условия для любого вида груза. </p><ul class="special-list" data-v-3e5570c3><li data-v-3e5570c3><strong data-v-3e5570c3>Хрупкие грузы:</strong> дополнительная упаковка и крепёж, осторожная погрузка</li><li data-v-3e5570c3><strong data-v-3e5570c3>Опасные грузы:</strong> лицензированный транспорт, оформление документов</li><li data-v-3e5570c3><strong data-v-3e5570c3>Температурный режим:</strong> рефрижераторы для скоропортящихся товаров</li><li data-v-3e5570c3><strong data-v-3e5570c3>Крупногабарит:</strong> тралы и низкорамные платформы</li></ul></section>',7)),t("section",_,[a[1]||(a[1]=t("h2",null,"Нужна консультация по доставке?",-1)),a[2]||(a[2]=t("p",null,"Свяжитесь с нами, и мы подберём оптимальный вариант для вашего груза!",-1)),e(c,{to:"/contacts",class:"cta-btn"},{default:o(()=>[...a[0]||(a[0]=[p("Связаться с нами",-1)])]),_:1})])])])}}}),k=h(y,[["__scopeId","data-v-3e5570c3"]]);export{k as default};
